mapper.select:
/* EventPromotionMapper.getPrizeComboList */ SELECT PRIZE_ID AS VALUE, PRIZE_NAME AS TEXT FROM NMCP_EVENT_PRMT_PRIZE@DL_MCP PRIZE, NMCP_EVENT_PRMT@DL_MCP PRMT WHERE PRIZE.PROMOTION_ID = PRMT.PROMOTION_ID AND PRMT.USE_YN = 'Y'
AND PRIZE.PROMOTION_ID = #{promotionId}
ORDER BY PRIZE_NAME
